'use client';

import Link from 'next/link';
import { usePathname } from 'next/navigation';
import { Briefcase, MessageSquare, Home, User, Compass, LayoutDashboard, Wallet, Search, Bell } from 'lucide-react';
import { cn } from '@/lib/utils';
import { useAuth } from '@/hooks/useAuth';

export default function BottomNavigation() {
    const pathname = usePathname();
    const { user } = useAuth();

    // Robust check: Auth User Type OR Pathname Context
    const isWorkerContext = user?.userType === 'worker' || pathname?.startsWith('/worker');

    const isActive = (route: string) => {
        if (route === '/dashboard' && pathname === '/dashboard') return true;
        if (route !== '/dashboard' && pathname?.startsWith(route)) return true;
        return false;
    };

    const customerItems = [
        { label: 'Home', icon: Home, route: '/dashboard' },
        { label: 'Explore', icon: Search, route: '/jobs' },
        { label: 'Activity', icon: Bell, route: '/tracking' }, // Replaced Message with Activity/Tracking as per typical flow
        { label: 'Profile', icon: User, route: '/customer/profile' },
    ];

    const workerItems = [
        { label: 'Home', icon: Home, route: '/worker/dashboard' },
        { label: 'Search', icon: Compass, route: '/worker/jobs/discovery' },
        { label: 'Chat', icon: MessageSquare, route: '/messages' }, // Shared or Worker specific
        { label: 'Wallet', icon: Wallet, route: '/worker/wallet' },
        { label: 'Profile', icon: User, route: '/worker/profile' },
    ];

    const navItems = isWorkerContext ? workerItems : customerItems;

    return (
        <nav className="fixed bottom-0 left-0 right-0 py-2 pb-6 sm:hidden z-50 transition-colors duration-300 bg-background/80 backdrop-blur-xl border-t border-border">
            <div className="flex justify-around items-end px-2">
                {navItems.map((item, idx) => {
                    const active = isActive(item.route);
                    const isCenter = isWorkerContext && idx === 1; // Example center logic if needed, removed for balance

                    return (
                        <Link
                            key={item.label}
                            href={item.route}
                            className={cn(
                                "flex flex-col items-center justify-center w-full py-2 transition-all duration-300 group",
                                active ? "text-primary" : "text-muted-foreground hover:text-foreground"
                            )}
                        >
                            <div className={cn(
                                "relative p-1.5 rounded-xl transition-all duration-300",
                                active ? "bg-primary/10 translate-y-[-4px]" : ""
                            )}>
                                <item.icon className={cn("h-6 w-6 transition-transform", active ? "scale-110" : "group-hover:scale-110")} />
                                {active && (
                                    <span className="absolute -bottom-1 left-1/2 w-1 h-1 bg-primary rounded-full transform -translate-x-1/2" />
                                )}
                            </div>
                            <span className={cn(
                                "text-[10px] font-bold mt-1 transition-all duration-300",
                                active ? "opacity-100 translate-y-[-2px]" : "opacity-0 h-0"
                            )}>
                                {item.label}
                            </span>
                        </Link>
                    );
                })}
            </div>
        </nav>
    );
}
